using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and communication." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS 101", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has authored two textbooks on Python programming.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 2, Title = "Data Structures & Algorithms", CourseCode = "CS 201", Description = "In-depth study of data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research focuses on algorithm optimization. He previously worked at a major tech company on distributed systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 3, Title = "Database Systems", CourseCode = "CS 340", Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez specializes in distributed databases and has consulted for several Fortune 500 companies on data architecture.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
        new() { Id = 4, Title = "Calculus I", CourseCode = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator who has developed innovative teaching methods for undergraduate mathematics.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
        new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to computer graphics and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Wright", InstructorBio = "Dr. Wright's research bridges pure mathematics and machine learning applications.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
        new() { Id = 6, Title = "Classical Mechanics", CourseCode = "PHYS 201", Description = "Newtonian mechanics, energy conservation, rotational dynamics, oscillations, and gravitation.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster has published extensively on computational physics and runs the university's physics simulation lab.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
        new() { Id = 7, Title = "Quantum Physics", CourseCode = "PHYS 310", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Priya Patel", InstructorBio = "Dr. Patel is an active researcher in quantum computing and brings cutting-edge insights to her teaching.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
        new() { Id = 8, Title = "Creative Writing", CourseCode = "ENG 210", Description = "Workshop-based course covering fiction, poetry, and creative nonfiction. Students develop a portfolio of original work.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a published novelist and poet whose work has appeared in several national literary magazines.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
        new() { Id = 9, Title = "American Literature", CourseCode = "ENG 330", Description = "Survey of American literary works from the colonial period to the present, with emphasis on cultural and historical context.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Lisa Hernandez", InstructorBio = "Dr. Hernandez is a specialist in 20th-century American fiction and has received multiple teaching awards.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
        new() { Id = 10, Title = "World History: 1500–Present", CourseCode = "HIST 102", Description = "Global history from the age of exploration through the modern era, covering political, economic, and cultural transformations.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Obi", InstructorBio = "Dr. Obi is an expert in comparative world history with fieldwork experience across three continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0;
    }
}

