arguments.file_text:
@page "/"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome! Browse our departments and courses, or enroll in a course today.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.DepartmentName</p>
                    <a href="courses/@course.Id" class="card-link">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?department=@dept.Id" class="card-link">Browse @dept.Code Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = [];
    private List<UniversityCourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@rendermode InteractiveServer
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <p class="text-muted">No courses match your search criteria.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="courses/@course.Id">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private string searchTerm = string.Empty;
    private int selectedDepartment;
    private List<UniversityCourseCatalog.Models.Department> departments = [];
    private List<UniversityCourseCatalog.Models.Course> filteredCourses = [];

    [SupplyParameterFromQuery(Name = "department")]
    public int? InitialDepartment { get; set; }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        if (InitialDepartment.HasValue)
            selectedDepartment = InitialDepartment.Value;
        UpdateResults();
    }

    private string SearchTerm
    {
        get => searchTerm;
        set { searchTerm = value; UpdateResults(); }
    }

    private int SelectedDepartment
    {
        get => selectedDepartment;
        set { selectedDepartment = value; UpdateResults(); }
    }

    private void UpdateResults()
    {
        filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartment > 0 ? selectedDepartment : null);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Your enrollment request has been received. You will be notified once it is processed.</p>
        <a href="courses">Browse more courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                           value="@Model.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                           value="@Model.StudentId" required />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="Model.CourseId" required>
                        <option value="">-- Select a Course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                                @course.CourseCode — @course.Title
                            </option>
                        }
                    </select>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "course")]
    public int? PreselectedCourse { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (PreselectedCourse.HasValue && Model.CourseId == 0)
            Model.CourseId = PreselectedCourse.Value;
    }

    private void HandleSubmit()
    {
        submitted = CatalogService.SubmitEnrollmentRequest(Model);
    }
}

