@page "/courses"
@rendermode InteractiveServer
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <p class="text-muted">No courses match your search criteria.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="courses/@course.Id">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private string searchTerm = string.Empty;
    private int selectedDepartment;
    private List<UniversityCourseCatalog.Models.Department> departments = [];
    private List<UniversityCourseCatalog.Models.Course> filteredCourses = [];

    [SupplyParameterFromQuery(Name = "department")]
    public int? InitialDepartment { get; set; }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        if (InitialDepartment.HasValue)
            selectedDepartment = InitialDepartment.Value;
        UpdateResults();
    }

    private string SearchTerm
    {
        get => searchTerm;
        set { searchTerm = value; UpdateResults(); }
    }

    private int SelectedDepartment
    {
        get => selectedDepartment;
        set { selectedDepartment = value; UpdateResults(); }
    }

    private void UpdateResults()
    {
        filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartment > 0 ? selectedDepartment : null);
    }
}

