@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Your enrollment request has been received. You will be notified once it is processed.</p>
        <a href="courses">Browse more courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                           value="@Model.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                           value="@Model.StudentId" required />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="Model.CourseId" required>
                        <option value="">-- Select a Course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                                @course.CourseCode — @course.Title
                            </option>
                        }
                    </select>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "course")]
    public int? PreselectedCourse { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (PreselectedCourse.HasValue && Model.CourseId == 0)
            Model.CourseId = PreselectedCourse.Value;
    }

    private void HandleSubmit()
    {
        submitted = CatalogService.SubmitEnrollmentRequest(Model);
    }
}

